using BuildingBlocks.Charts;using DashboardCharts.Domain;using Microsoft.EntityFrameworkCore;using Microsoft.Extensions.DependencyInjection;using Microsoft.Extensions.Hosting;using Microsoft.Extensions.Logging;using System.Text.Json;
namespace DashboardCharts.Persistence.Seed;/** <summary>Default palette.</summary> */ public static class DashboardPalette{/** <summary>Colors.</summary> */ public static readonly IReadOnlyList<string>Colors=["#2563EB","#16A34A","#DC2626","#D97706","#7C3AED","#0891B2","#DB2777","#65A30D"];}
/** <summary>Dashboard seeder.</summary> */ public static class DashboardChartsSeeder{/** <summary>Seeds default charts.</summary> */ public static async Task SeedAsync(DashboardChartsDbContext db,CancellationToken ct){var colors=JsonSerializer.Serialize(DashboardPalette.Colors);var specs=new[]{("العملاء حسب الحالة",ChartType.Pie,"clients","status",(string?)null,ChartAggregation.Count),("المصروفات حسب الفئة",ChartType.Bar,"expenses","category","amount",ChartAggregation.Sum),("المهام حسب الأولوية",ChartType.Bar,"todos","priority",(string?)null,ChartAggregation.Count),("المصروفات عبر الزمن",ChartType.Line,"expenses","date","amount",ChartAggregation.Sum)};var existing=await db.Charts.Select(x=>x.Title).ToListAsync(ct);var order=0;foreach(var s in specs){if(!existing.Contains(s.Item1))db.Charts.Add(ChartDefinition.Create(s.Item1,s.Item2,s.Item3,s.Item4,s.Item5,s.Item6,colors,null,order).Value);order++;}await db.SaveChangesAsync(ct);}}
/** <summary>Seed host.</summary> */ public sealed class DashboardChartsSeedHostedService(IServiceProvider services,BuildingBlocks.Persistence.DatabaseInitializationState<DashboardChartsDbContext> initialization,ILogger<DashboardChartsSeedHostedService> logger):IHostedService{/** <inheritdoc/> */ public async Task StartAsync(CancellationToken ct){if(!initialization.IsFirstRun){logger.LogInformation("Dashboard charts seed skipped: database already initialized.");return;}try{using var scope=services.CreateScope();await DashboardChartsSeeder.SeedAsync(scope.ServiceProvider.GetRequiredService<DashboardChartsDbContext>(),ct);logger.LogInformation("Dashboard charts seed completed.");}catch(Exception ex){logger.LogWarning(ex,"Dashboard charts seed skipped.");}}/** <inheritdoc/> */ public Task StopAsync(CancellationToken ct)=>Task.CompletedTask;}
